input.command:
MONGO_PASS=$(kubectl get secret admin-user-password -n mongodb -o jsonpath='{.data.password}' | base64 -d)
kubectl exec -n mongodb mongodb-replica-0 -- mongosh --quiet "mongodb://admin-user:${MONGO_PASS}@localhost:27017/admin?directConnection=true" --eval '
var s = rs.status();
s.members.forEach(m => print(m.name + " | " + m.stateStr));
' 2>&1

MONGO_PASS=$(kubectl get secret admin-user-password -n mongodb -o jsonpath='{.data.password}' | base64 -d)
kubectl exec -n mongodb mongodb-replica-0 -- mongosh --quiet "mongodb://admin-user:${MONGO_PASS}@localhost:27017/admin?directConnection=true" --eval '
var v = db.adminCommand({getParameter:1, logLevel:1}).logLevel;
var p = db.getProfilingStatus();
print("verbosity=" + v + " slowms=" + p.slowms);
' 2>&1

MONGO_PASS=$(kubectl get secret admin-user-password -n mongodb -o jsonpath='{.data.password}' | base64 -d)
for i in 0 1 2 3 4; do
  out=$(kubectl exec -n mongodb mongodb-replica-$i -- mongosh --quiet "mongodb://admin-user:${MONGO_PASS}@localhost:27017/admin?directConnection=true" --eval '
var v = db.adminCommand({getParameter:1, logLevel:1}).logLevel;
var p = db.getProfilingStatus();
var c = db.adminCommand({getCmdLineOpts:1});
var wt = (c.parsed && c.parsed.storage && c.parsed.storage.wiredTiger && c.parsed.storage.wiredTiger.engineConfig) ? c.parsed.storage.wiredTiger.engineConfig.journalCompressor : "default";
print("verbosity=" + v + " slowms=" + p.slowms + " compression=" + wt);
' 2>&1)
  echo "Pod $i: $out"
done

MONGO_PASS=$(kubectl get secret admin-user-password -n mongodb -o jsonpath='{.data.password}' | base64 -d)
kubectl exec -n mongodb mongodb-replica-0 -- mongosh --quiet "mongodb://admin-user:${MONGO_PASS}@localhost:27017/admin?directConnection=true" --eval '
var p = db.getProfilingStatus();
print(JSON.stringify(p));
var c = db.adminCommand({getCmdLineOpts:1});
print(JSON.stringify(c.parsed));
' 2>&1

MONGO_PASS=$(kubectl get secret admin-user-password -n mongodb -o jsonpath='{.data.password}' | base64 -d)
for i in 0 1 2 3 4; do
  echo "=== Pod $i ==="
  kubectl exec -n mongodb mongodb-replica-$i -- mongosh --quiet \
    "mongodb://admin-user:${MONGO_PASS}@localhost:27017/admin?directConnection=true" \
    --eval '
db.adminCommand({setParameter: 1, logLevel: 2});
db.setProfilingLevel(db.getProfilingStatus().was, {slowms: 200});
var v = db.adminCommand({getParameter:1, logLevel:1}).logLevel;
var p = db.getProfilingStatus();
print("verbosity=" + v + " slowms=" + p.slowms);
' 2>&1
done

