input.command:
MONGO_PASS=$(kubectl get secret admin-user-password -n mongodb -o jsonpath='{.data.password}' | base64 -d)
kubectl exec -n mongodb mongodb-replica-4 -- mongosh --quiet \
  "mongodb://admin-user:${MONGO_PASS}@localhost:27017/admin?directConnection=true" \
  --eval '
var s = rs.status();
print("RS: " + s.set + " ok=" + s.ok);
s.members.forEach(m => print("  " + m.name.split(".")[0] + " | " + m.stateStr + " | health=" + m.health));
' 2>&1
